/** Type AST definitions */
interface Type {
  <ResType> ResType accept(TypeVisitor<ResType> v);
}

interface TypeVisitor<ResType> {
  ResType forIntType();
  ResType forBoolType();
  ResType forUnitType();
  ResType forListType(ListType t);
  ResType forRefType(RefType t);
  ResType forFunType(FunType t);
}

class IntType implements Type {
  public static final IntType ONLY = new IntType();
  private IntType() {}
  public <ResType> ResType accept(TypeVisitor<ResType> v) { return v.forIntType(); }
  public String toString() { return "int"; }
}

class BoolType implements Type {
