  private UnitType() {}
  public <ResType> ResType accept(TypeVisitor<ResType> v) { return v.forUnitType(); }
  public String toString() { return "unit"; }
}

class ListType implements Type {
  private Type elemType;
  ListType(Type t) { elemType = t; }
  public Type elemType() { return elemType; }
  public <ResType> ResType accept(TypeVisitor<ResType> v) { return v.forListType(this); }
  public String toString() { return "list " + elemType; }
  public boolean equals(Object other) {
    return (other instanceof ListType) && elemType.equals(((ListType)other).elemType);
  }
}

class RefType implements Type {
  private Type elemType;
  RefType(Type t) { elemType = t; }
  public Type elemType() { return elemType; }
  public <ResType> ResType accept(TypeVisitor<ResType> v) { return v.forRefType(this); }
  public String toString() { return "ref " + elemType; }
  public boolean equals(Object other) {
    return (other instanceof RefType) && elemType.equals(((RefType)other).elemType);
  }
}

class FunType implements Type {
  private Type[] argTypes;
  private Type resultType;
  FunType(Type[] args, Type result) { argTypes = args; resultType = result; }
  public Type[] argTypes() { return argTypes; }
  public Type resultType() { return resultType; }
  public <ResType> ResType accept(TypeVisitor<ResType> v) { return v.forFunType(this); }
  public String toString() {
    return "(" + ToString.toString(argTypes, ", ") + " -> " + resultType + ")";
  }
  public boolean equals(Object other) {
    if (!(other instanceof FunType)) return false;
    FunType o = (FunType) other;
    if (!resultType.equals(o.resultType)) return false;
    if (argTypes.length != o.argTypes.length) return false;
    for (int i = 0; i < argTypes.length; i++) {
      if (!argTypes[i].equals(o.argTypes[i])) return false;
    }
    return true;
  }
}

