/** A class representing a Jam reference cell (box).  A reference cell is a mutable container
  * holding a single JamVal.  Reference cells support the ref, !, and <- operations.
  * Note: JamRef uses reference identity for equals() (inherited from Object) because two
  * reference cells are equal only if they are the same cell, not merely if they contain the
  * same value.  This is the standard semantics for mutable reference types. */
class JamRef implements JamVal {
  private JamVal value;

  JamRef(JamVal v) { value = v; }

  /** Returns the value stored in this reference cell. */
  public JamVal value() { return value; }

  /** Updates the value stored in this reference cell. */
  public void setValue(JamVal v) { value = v; }

  public <ResType> ResType accept(JamValVisitor<ResType> jvv) { return jvv.forJamRef(this); }

  public String toString() { return "(ref " + value + ")"; }
}

