class Let implements AST {
  private Def[] defs;
  private AST body;
  Let(Def[] d, AST b) { defs = d; body = b; }

  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forLet(this); }
  public Def[] defs() { return defs; }
  public AST body() { return body; }
  public String toString() { 
    return "let " + ToString.toString(defs," ") + " in " + body; 
  }

  /* Commonly used non-essential methods */
  /** Returns the vars that are locally defined in this Let. */
  public TypedId[] vars() {
    int n = defs.length;
    TypedId[] vars = new TypedId[n];
    for(int i = 0; i < n; i++) { vars[i] = defs[i].lhs(); }
    return vars;
  }
  /** Returns the exps that appear on the rhs of defs in this Let. */
  public AST[] exps() {
    int n = defs.length;
    AST[] exps = new AST[n];
    for(int i = 0; i < n; i++) { exps[i] = defs[i].rhs(); }
    return exps;
  }
}

/** A Block is a non-empty sequence of statements (expressions) that returns the value of the last
  * statement (expression).  The preceding statements are included solely for their side-effect
  * (changes to the values stored in boxes)
  * Hence, a block cannot appear as the first argument in a binary operation unless it is
  * enclosed in parentheses. The empty block is a parser error (ParseException).
  */
class Block implements AST {
  private AST[] exps;
  public Block(AST[] es) {
    exps = es;
  }

  public <ResType> ResType accept(ASTVisitor<ResType> v) { return v.forBlock(this); }

  public AST[] exps() { return exps; }

  public String toString() {
    return "{" + ToString.toString(exps, "; ") + "}";
  }
}

