/** 
  * Interpreter for Typed Jam.
  */

import java.io.IOException;
import java.io.Reader;
import java.util.HashMap;

/** The exception class for Jam run-time errors during program evaluation. */
class EvalException extends RuntimeException {
  EvalException(String msg) { super(msg); }
}

/** The exception class for Jam type errors. */
class TypeException extends RuntimeException {
  TypeException(String msg) { super(msg); }
}

/** Interpreter class supporting eager and lazy evaluation for Jam programs. */
class Interpreter {
  /** Parser to use. */
  Parser parser;  // initialized in constructors

  /** Parsed AST. */
  AST prog;       // initialized in constructors

  Interpreter(String fileName) throws IOException {
    parser = new Parser(fileName);
    prog = parser.parseAndCheck();
  }

  Interpreter(Parser p) {
    parser = p;
    prog = parser.parseAndCheck();
  }

  Interpreter(Reader reader) {
    parser = new Parser(reader);
    prog = parser.parseAndCheck();
  }

  /* Interpreter API: the public methods of this Jam Interpreter */

  public JamVal eagerEval() {
    checkTypes(prog);
    return prog.accept(valueValueVisitor);
  }

  public JamVal lazyEval() {
    checkTypes(prog);
    return prog.accept(valueNeedVisitor);
  }

  public void checkTypes(AST prog) {
    prog.accept(new TypeChecker());
  }

  /* Interfaces that support different forms of variable binding and different forms of list construction */

  /** The interface supported by various binding evaluation policies. */
  interface BindingPolicy {
    Binding newBinding(Variable var, AST ast, EvalVisitor ev);
    Binding newDummyBinding(Variable var);
  }

  /** Interface containing a factory to build the cons object specified by this ConsPolicy. */
  interface ConsPolicy {
    JamVal evalCons(AST[] args, EvalVisitor ev);
  }

  /** Class representing a binding in CBV evaluation. */ 
  static class ValueBinding extends Binding {
    ValueBinding(Variable v, JamVal jv) { super(v, jv); }
    public JamVal value() { 
      if (value == null) illegalForwardReference(var());
      return value; 
    }
    public void setBinding(Suspension s) { value = s.eval(); }
    public String toString() { return "[" + var + ", " + value + "]"; }
  }

  /** Class representing a binding in CBNeed evaluation. */
  static class NeedBinding extends Binding {
    private Suspension susp;
    NeedBinding(Variable v, Suspension s) { 
      super(v,null);
      susp = s;
    }
    public JamVal value() {
      if (value == null) {
        if (susp == null) illegalForwardReference(var());
        else {
          value = susp.eval();
          susp = null;
        }
      }
      return value;
    }
    public void setBinding(Suspension s) { susp = s; value = null; }
    public String toString() { return "[" + var + ", " + value + ", " + susp + "]"; }
  }

  static JamVal illegalForwardReference(Variable v) {
    throw new EvalException("Attempt to evaluate variable " + v + " bound to null, indicating an illegal forward reference");
  }

  static final BindingPolicy CALL_BY_VALUE = new BindingPolicy() {
    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) { return new ValueBinding(var, arg.accept(ev)); }
    public Binding newDummyBinding(Variable var) { return new ValueBinding(var, null); }
  };

  static final BindingPolicy CALL_BY_NEED = new BindingPolicy() {
    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      return new NeedBinding(var, new ConcreteSuspension(arg, ev));
    }
    public Binding newDummyBinding(Variable var) { return new NeedBinding(var, null); }
  };

  static class ConcreteSuspension implements Suspension {
    private AST exp;
    private EvalVisitor ev;  
    ConcreteSuspension(AST a, EvalVisitor e) { exp = a; ev = e; }
    public JamVal eval() { return exp.accept(ev); } 
    public String toString() { return "<" + exp + ", " + ev + ">"; }
  }

  static class JamLazyNeedCons extends JamCons {
    protected Suspension firstSusp, restSusp;
    public JamLazyNeedCons(AST f, AST r, EvalVisitor ev) {
      super(null, null);
      firstSusp = new ConcreteSuspension(f, ev);
      restSusp = new ConcreteSuspension(r, ev);
    }
    public JamVal first() {
      if (first == null) {
        first = firstSusp.eval();
        firstSusp = null;
      }
      return first;
    }
    public JamList rest() {
      if (rest == null) {
        rest = checkList(restSusp.eval());
        restSusp = null;
      }
      return (JamList)rest;
    }
  }

  public static final ConsPolicy EAGER = new ConsPolicy() {
    public JamVal evalCons(AST[] args, EvalVisitor ev) {
      JamVal val0 = args[0].accept(ev);
      JamVal val1 = args[1].accept(ev);
      if (val1 instanceof JamList) return new JamCons(val0, (JamList)val1);
      throw new EvalException("Second argument " + val1 + " to `cons' is not a JamList");
    }
  };

  public static final ConsPolicy LAZYNEED = new ConsPolicy() {
    public JamVal evalCons(AST[] args, EvalVisitor ev) { return new JamLazyNeedCons(args[0], args[1], ev); }
  };

  static final ASTVisitor<JamVal> valueValueVisitor = new EvalVisitor(CALL_BY_VALUE, EAGER);
  static final ASTVisitor<JamVal> valueNeedVisitor = new EvalVisitor(CALL_BY_VALUE, LAZYNEED);

  static class EvalVisitor implements ASTVisitor<JamVal> {
    PureList<Binding> env;
    BindingPolicy bindingPolicy;
    ConsPolicy consPolicy;

    private EvalVisitor(PureList<Binding> e, BindingPolicy bp, ConsPolicy cp) {
      env = e;
      bindingPolicy = bp;
      consPolicy = cp;
    }

    public EvalVisitor(BindingPolicy bp, ConsPolicy cp) { this(new Empty<Binding>(), bp, cp); }

    public EvalVisitor newEvalVisitor(PureList<Binding> env) {
      return new EvalVisitor(env, bindingPolicy, consPolicy);
    }

    public JamVal forBoolConstant(BoolConstant b) { return b; }
    public JamVal forIntConstant(IntConstant i) { return i; }
    public JamVal forEmptyConstant(EmptyConstant n) { return JamEmpty.ONLY; }

    public JamVal forVariable(Variable v) {
      Binding match = env.accept(new LookupVisitor<Binding>(v));
      if (match == null) throw new EvalException("variable " + v + " is unbound");
      return match.value();
    }

    public JamVal forPrimFun(PrimFun f) { return f; }
    public JamVal forUnOpApp(UnOpApp u) { return u.rator().accept(new UnOpEvaluator(u.arg().accept(this))); }
    public JamVal forBinOpApp(BinOpApp b) { return b.rator().accept(new BinOpEvaluator(b.arg1(), b.arg2())); }

    public JamVal forApp(App a) {
      JamVal rator = a.rator().accept(this);
      if (rator instanceof JamFun) return ((JamFun)rator).accept(new FunEvaluator(a.args()));
      throw new EvalException(rator + " appears at head of application " + a + " but it is not a valid function");
    }

    public JamVal forMap(Map m) { return new JamClosure(m, env); }

    public JamVal forIf(If i) {
      JamVal test = i.test().accept(this);
      if (!(test instanceof BoolConstant)) throw new EvalException("non Boolean " + test + " used as test in if");
      if (test == BoolConstant.TRUE) return i.conseq().accept(this);
      return i.alt().accept(this);
    }

    public JamVal forBlock(Block b) {
      AST[] exps = b.exps();
      JamVal result = null;
      for (AST e : exps) result = e.accept(this);
      return result;
    }

    public JamVal forLet(Let l) {
      TypedId[] tids = l.vars();
      AST[] exps = l.exps();
      int n = tids.length;
      PureList<Binding> newEnv = env;
      Binding[] bindings = new Binding[n];
      for(int i = 0; i < n; i++) {
        bindings[i] = bindingPolicy.newDummyBinding(tids[i].id());
        newEnv = newEnv.cons(bindings[i]);
      }
      EvalVisitor newEV = newEvalVisitor(newEnv); 
      for(int i = 0; i < n; i++) {
        bindings[i].setBinding(new ConcreteSuspension(exps[i], newEV));
      }
      return l.body().accept(newEV);
    }

    class FunEvaluator implements JamFunVisitor<JamVal> {
      AST[] args;
      FunEvaluator(AST[] asts) { args = asts; }

      PrimFunVisitor<JamVal> primEvaluator = new PrimFunVisitor<JamVal>() {
        private JamVal[] evalArgs() {
          JamVal[] vals = new JamVal[args.length];
          for(int i = 0; i < args.length; i++) vals[i] = args[i].accept(EvalVisitor.this);
          return vals;
        }
        private void primFunError(String fn) { throw new EvalException("Primitive function `" + fn + "' applied to " + args.length + " arguments"); }
        private JamCons evalJamConsArg(AST arg, String fun) {
          JamVal val = arg.accept(EvalVisitor.this);
          if (val instanceof JamCons) return (JamCons)val;
          throw new EvalException("Primitive function `" + fun + "' applied to argument " + val + " that is not a JamCons");
        }
        public JamVal forConsPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("cons?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamCons);
        }
        public JamVal forEmptyPPrim() {
          JamVal[] vals = evalArgs();
          if (vals.length != 1) primFunError("empty?");
          return BoolConstant.toBoolConstant(vals[0] instanceof JamEmpty);
        }
        public JamVal forConsPrim() {
          if (args.length != 2) primFunError("cons");
          return consPolicy.evalCons(args, EvalVisitor.this);
        }
        public JamVal forFirstPrim() { 
          if (args.length != 1) primFunError("first");
          return evalJamConsArg(args[0], "first").first(); 
        }
        public JamVal forRestPrim() { 
          if (args.length != 1) primFunError("rest");
          return evalJamConsArg(args[0], "rest").rest(); 
        }
      };

      public JamVal forJamClosure(JamClosure closure) {
        Map map = closure.code();
        TypedId[] tids = map.vars();
        if (tids.length != args.length) throw new EvalException("closure applied to " + args.length + " arguments");
        PureList<Binding> newEnv = closure.env();
        for(int i = 0; i < tids.length; i++) {
          newEnv = newEnv.cons(bindingPolicy.newBinding(tids[i].id(), args[i], EvalVisitor.this));
        }
        return map.body().accept(newEvalVisitor(newEnv));
      }
      public JamVal forPrimFun(PrimFun primFun) { return primFun.accept(primEvaluator); }
    }

    static class UnOpEvaluator implements UnOpVisitor<JamVal> {
      private JamVal val;
      UnOpEvaluator(JamVal jv) { val = jv; }
      private IntConstant checkInteger(String op) {
        if (val instanceof IntConstant) return (IntConstant)val;
        throw new EvalException("Unary operator `" + op + "' applied to non-integer " + val);
      }
      private BoolConstant checkBoolean(String op) {
        if (val instanceof BoolConstant) return (BoolConstant)val;
        throw new EvalException("Unary operator `" + op + "' applied to non-boolean " + val);
      }
      private JamRef checkRef(String op) {
        if (val instanceof JamRef) return (JamRef) val;
        throw new EvalException("Unary operator `" + op + "' applied to non-ref " + val);
      }
      public JamVal forUnOpPlus() { return checkInteger("+"); }
      public JamVal forUnOpMinus() { return new IntConstant(-checkInteger("-").value()); }
      public JamVal forOpTilde() { return checkBoolean("~").not(); }
      public JamVal forOpBang() { return checkRef("!").value(); }
      public JamVal forOpRef() { return new JamRef(val); }
    }

    class BinOpEvaluator implements BinOpVisitor<JamVal> {
      private AST arg1, arg2;
      BinOpEvaluator(AST a1, AST a2) { arg1 = a1; arg2 = a2; }
      private IntConstant evalIntegerArg(AST arg, String b) {
        JamVal val = arg.accept(EvalVisitor.this);
        if (val instanceof IntConstant) return (IntConstant)val;
        throw new EvalException("Binary operator `" + b + "' applied to non-integer " + val);
      }
      private BoolConstant evalBooleanArg(AST arg, String b) {
        JamVal val = arg.accept(EvalVisitor.this);
        if (val instanceof BoolConstant) return (BoolConstant)val;
        throw new EvalException("Binary operator `" + b + "' applied to non-boolean " + val);
      }
      public JamVal forBinOpPlus() { return new IntConstant(evalIntegerArg(arg1,"+").value() + evalIntegerArg(arg2, "+").value()); }
      public JamVal forBinOpMinus() { return new IntConstant(evalIntegerArg(arg1,"-").value() - evalIntegerArg(arg2, "-").value()); }
      public JamVal forOpTimes() { return new IntConstant(evalIntegerArg(arg1,"*").value() * evalIntegerArg(arg2, "*").value()); }
      public JamVal forOpDivide() {
        int divisor = evalIntegerArg(arg2, "/").value();
        if (divisor == 0) throw new EvalException("Attempt to divide by zero");
        return new IntConstant(evalIntegerArg(arg1,"/").value() / divisor);
      }
      public JamVal forOpEquals() { return BoolConstant.toBoolConstant(arg1.accept(EvalVisitor.this).equals(arg2.accept(EvalVisitor.this))); }
      public JamVal forOpNotEquals() { return BoolConstant.toBoolConstant(!arg1.accept(EvalVisitor.this).equals(arg2.accept(EvalVisitor.this))); }
      public JamVal forOp_LessThan() { return BoolConstant.toBoolConstant(evalIntegerArg(arg1, "<").value() < evalIntegerArg(arg2, "<").value()); }
      public JamVal forOp_GreaterThan() { return BoolConstant.toBoolConstant(evalIntegerArg(arg1, ">").value() > evalIntegerArg(arg2, ">").value()); }
      public JamVal forOp_LessThanEquals() { return BoolConstant.toBoolConstant(evalIntegerArg(arg1, "<=").value() <= evalIntegerArg(arg2, "<=").value()); }
      public JamVal forOp_GreaterThanEquals() { return BoolConstant.toBoolConstant(evalIntegerArg(arg1, ">=").value() >= evalIntegerArg(arg2, ">=").value()); }
      public JamVal forOpAnd() {
        BoolConstant b1 = evalBooleanArg(arg1, "&");
        if (b1 == BoolConstant.FALSE) return BoolConstant.FALSE;
        return evalBooleanArg(arg2, "&");
      }
      public JamVal forOpOr() {
        BoolConstant b1 = evalBooleanArg(arg1, "|");
        if (b1 == BoolConstant.TRUE) return BoolConstant.TRUE;
        return evalBooleanArg(arg2, "|");
      }
      public JamVal forOpGets() {
        JamVal val1 = arg1.accept(EvalVisitor.this);
        if (!(val1 instanceof JamRef)) throw new EvalException("Binary operator `<-' applied to non-ref " + val1);
        JamVal val2 = arg2.accept(EvalVisitor.this);
        ((JamRef) val1).setValue(val2);
        return JamUnit.ONLY;
      }
      // Added missing methods for BinOpVisitor
      public JamVal forOpLessThan() { return forOp_LessThan(); }
      public JamVal forOpGreaterThan() { return forOp_GreaterThan(); }
      public JamVal forOpLessThanEquals() { return forOp_LessThanEquals(); }
      public JamVal forOpGreaterThanEquals() { return forOp_GreaterThanEquals(); }
    }
  }

  class TypeChecker implements ASTVisitor<Type> {
    private java.util.Map<Variable, Type> env;
    TypeChecker() { env = new HashMap<Variable, Type>(); }
    TypeChecker(java.util.Map<Variable, Type> e) { env = e; }

    public Type forIntConstant(IntConstant i) { return IntType.ONLY; }
    public Type forBoolConstant(BoolConstant b) { return BoolType.ONLY; }
    public Type forEmptyConstant(EmptyConstant n) { return new ListType(n.type()); }
    public Type forVariable(Variable v) {
      Type t = env.get(v);
      if (t == null) throw new TypeException("Variable " + v + " is not typed");
      return t;
    }
    public Type forPrimFun(PrimFun f) { return null; }
    public Type forUnOpApp(UnOpApp u) { return u.rator().accept(new UnOpTypeChecker(u.arg().accept(this))); }
    public Type forBinOpApp(BinOpApp b) { return b.rator().accept(new BinOpTypeChecker(b.arg1().accept(this), b.arg2().accept(this))); }
    public Type forApp(App a) {
      if (a.rator() instanceof PrimFun) return ((PrimFun)a.rator()).accept(new PrimTypeChecker(a.args()));
      Type ratorType = a.rator().accept(this);
      if (!(ratorType instanceof FunType)) throw new TypeException("Applying non-function " + a.rator());
      FunType ft = (FunType) ratorType;
      Type[] argTypes = ft.argTypes();
      AST[] args = a.args();
      if (argTypes.length != args.length) throw new TypeException("Arity mismatch");
      for (int i = 0; i < args.length; i++) {
        Type actual = args[i].accept(this);
        if (!actual.equals(argTypes[i])) throw new TypeException("Argument type mismatch");
      }
      return ft.resultType();
    }
    public Type forIf(If i) {
      if (i.test().accept(this) != BoolType.ONLY) throw new TypeException("If test must be bool");
      Type t1 = i.conseq().accept(this);
      Type t2 = i.alt().accept(this);
      if (!t1.equals(t2)) throw new TypeException("If branches must have same type");
      return t1;
    }
    public Type forMap(Map m) {
      TypedId[] tids = m.vars();
      Type[] argTypes = new Type[tids.length];
      java.util.Map<Variable, Type> newEnv = new HashMap<Variable, Type>(env);
      for (int i = 0; i < tids.length; i++) {
        argTypes[i] = tids[i].type();
        newEnv.put(tids[i].id(), tids[i].type());
      }
      return new FunType(argTypes, m.body().accept(new TypeChecker(newEnv)));
    }
    public Type forLet(Let l) {
      TypedId[] tids = l.vars();
      AST[] exps = l.exps();
      java.util.Map<Variable, Type> newEnv = new HashMap<Variable, Type>(env);
      for (TypedId tid : tids) newEnv.put(tid.id(), tid.type());
      TypeChecker bodyChecker = new TypeChecker(newEnv);
      for (int i = 0; i < tids.length; i++) {
        if (!exps[i].accept(bodyChecker).equals(tids[i].type())) throw new TypeException("Let RHS type mismatch");
      }
      return l.body().accept(bodyChecker);
    }
    public Type forBlock(Block b) {
      Type last = null;
      for (AST e : b.exps()) last = e.accept(this);
      return last;
    }

    class UnOpTypeChecker implements UnOpVisitor<Type> {
      Type argType;
      UnOpTypeChecker(Type t) { argType = t; }
      public Type forUnOpPlus() { if (argType != IntType.ONLY) throw new TypeException("+ expects int"); return IntType.ONLY; }
      public Type forUnOpMinus() { if (argType != IntType.ONLY) throw new TypeException("- expects int"); return IntType.ONLY; }
      public Type forOpTilde() { if (argType != BoolType.ONLY) throw new TypeException("~ expects bool"); return BoolType.ONLY; }
      public Type forOpBang() { if (!(argType instanceof RefType)) throw new TypeException("! expects ref"); return ((RefType)argType).elemType(); }
      public Type forOpRef() { return new RefType(argType); }
    }

    class BinOpTypeChecker implements BinOpVisitor<Type> {
      Type t1, t2;
      BinOpTypeChecker(Type a1, Type a2) { t1 = a1; t2 = a2; }
      public Type forBinOpPlus() { if (t1 != IntType.ONLY || t2 != IntType.ONLY) throw new TypeException("+ expects int"); return IntType.ONLY; }
      public Type forBinOpMinus() { if (t1 != IntType.ONLY || t2 != IntType.ONLY) throw new TypeException("- expects int"); return IntType.ONLY; }
      public Type forOpTimes() { if (t1 != IntType.ONLY || t2 != IntType.ONLY) throw new TypeException("* expects int"); return IntType.ONLY; }
      public Type forOpDivide() { if (t1 != IntType.ONLY || t2 != IntType.ONLY) throw new TypeException("/ expects int"); return IntType.ONLY; }
      public Type forOpLessThan() { if (t1 != IntType.ONLY || t2 != IntType.ONLY) throw new TypeException("< expects int"); return BoolType.ONLY; }
      public Type forOpGreaterThan() { if (t1 != IntType.ONLY || t2 != IntType.ONLY) throw new TypeException("> expects int"); return BoolType.ONLY; }
      public Type forOpLessThanEquals() { if (t1 != IntType.ONLY || t2 != IntType.ONLY) throw new TypeException("<= expects int"); return BoolType.ONLY; }
      public Type forOpGreaterThanEquals() { if (t1 != IntType.ONLY || t2 != IntType.ONLY) throw new TypeException(">= expects int"); return BoolType.ONLY; }
      public Type forOpAnd() { if (t1 != BoolType.ONLY || t2 != BoolType.ONLY) throw new TypeException("& expects bool"); return BoolType.ONLY; }
      public Type forOpOr() { if (t1 != BoolType.ONLY || t2 != BoolType.ONLY) throw new TypeException("| expects bool"); return BoolType.ONLY; }
      public Type forOpEquals() { if (!t1.equals(t2)) throw new TypeException("= expects same types"); return BoolType.ONLY; }
      public Type forOpNotEquals() { if (!t1.equals(t2)) throw new TypeException("!= expects same types"); return BoolType.ONLY; }
      public Type forOpGets() {
        if (!(t1 instanceof RefType)) throw new TypeException("<- expects ref");
        if (!((RefType)t1).elemType().equals(t2)) throw new TypeException("<- type mismatch");
        return UnitType.ONLY;
      }
    }

    class PrimTypeChecker implements PrimFunVisitor<Type> {
      AST[] args;
      PrimTypeChecker(AST[] a) { args = a; }
      private void checkArity(int expected, String name) { if (args.length != expected) throw new TypeException(name + " expects " + expected + " args"); }
      public Type forConsPrim() {
        checkArity(2, "cons");
        Type t1 = args[0].accept(TypeChecker.this);
        Type t2 = args[1].accept(TypeChecker.this);
        if (!(t2 instanceof ListType)) throw new TypeException("cons expects list");
        if (!t1.equals(((ListType)t2).elemType())) throw new TypeException("cons mismatch");
        return t2;
      }
      public Type forFirstPrim() {
        checkArity(1, "first");
        Type t = args[0].accept(TypeChecker.this);
        if (!(t instanceof ListType)) throw new TypeException("first expects list");
        return ((ListType)t).elemType();
      }
      public Type forRestPrim() {
        checkArity(1, "rest");
        Type t = args[0].accept(TypeChecker.this);
        if (!(t instanceof ListType)) throw new TypeException("rest expects list");
        return t;
      }
      public Type forEmptyPPrim() {
        checkArity(1, "empty?");
        if (!(args[0].accept(TypeChecker.this) instanceof ListType)) throw new TypeException("empty? expects list");
        return BoolType.ONLY;
      }
      public Type forConsPPrim() {
        checkArity(1, "cons?");
        if (!(args[0].accept(TypeChecker.this) instanceof ListType)) throw new TypeException("cons? expects list");
        return BoolType.ONLY;
      }
    }
  }
}

import junit.framework.TestCase;
import java.io.*;

public class MyAssign5Test extends TestCase {
  public MyAssign5Test(String name) { super(name); }

  private void typeErrorCheck(String name, String program) {
    try {
      Interpreter interp = new Interpreter(new StringReader(program));
      interp.eagerEval();
      fail(name + " should have thrown TypeException");
    } catch (TypeException e) {
      // success
    }
  }

  private void evalCheck(String program, String expected) {
    Interpreter interp = new Interpreter(new StringReader(program));
    assertEquals(expected, interp.eagerEval().toString());
    interp = new Interpreter(new StringReader(program));
    assertEquals(expected, interp.lazyEval().toString());
  }

  public void testTypeErrors() {
    typeErrorCheck("plus-bool", "1 + true");
    typeErrorCheck("if-int", "if 1 then 2 else 3");
    typeErrorCheck("if-mismatch", "if true then 1 else false");
    typeErrorCheck("app-non-fun", "1(2)");
    typeErrorCheck("arity-mismatch", "(map x:int to x)(1, 2)");
    typeErrorCheck("arg-type-mismatch", "(map x:int to x)(true)");
    typeErrorCheck("let-rhs-mismatch", "let x:int := true; in x");
    typeErrorCheck("cons-mismatch", "cons(1, empty:bool)");
    typeErrorCheck("first-non-list", "first(1)");
    typeErrorCheck("rest-non-list", "rest(1)");
    typeErrorCheck("emptyP-non-list", "empty?(1)");
    typeErrorCheck("bang-non-ref", "!(1)");
    typeErrorCheck("gets-non-ref", "1 <- 2");
    typeErrorCheck("gets-mismatch", "let x:ref int := ref 1; in x <- true");
  }

  public void testPolymorphic() {
    evalCheck("cons(1, empty:int)", "(1)");
    evalCheck("first(cons(true, empty:bool))", "true");
    evalCheck("rest(cons(1, empty:int))", "()");
    evalCheck("empty?(empty:unit)", "true");
    evalCheck("cons?(cons(1, empty:int))", "true");
    evalCheck("let x:ref int := ref 1; in !x", "1");
    evalCheck("let x:ref int := ref 1; in {x <- 2; !x}", "2");
    evalCheck("1 = 1", "true");
    evalCheck("1 = 2", "false");
    evalCheck("true = true", "true");
    evalCheck("empty:int = empty:int", "true");
  }

  public void testComplexTypes() {
    evalCheck("let f: (int -> int) := map x:int to x + 1; in f(5)", "6");
    evalCheck("let f: ((int -> int), int -> int) := map g:(int -> int), x:int to g(x); in f(map y:int to y*y, 3)", "9");
  }
}

